async () => {
  const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));
  const down = new Set();
  const setKey = (key, pressed) => {
    if (pressed && !down.has(key)) {
      down.add(key);
      window.dispatchEvent(new KeyboardEvent('keydown', { key, bubbles: true, cancelable: true }));
    }
    if (!pressed && down.has(key)) {
      down.delete(key);
      window.dispatchEvent(new KeyboardEvent('keyup', { key, bubbles: true, cancelable: true }));
    }
  };
  const releaseAll = () => [...down].forEach((key) => setKey(key, false));

  window.dispatchEvent(new KeyboardEvent('keydown', { key: 'r', bubbles: true, cancelable: true }));
  window.dispatchEvent(new KeyboardEvent('keyup', { key: 'r', bubbles: true, cancelable: true }));
  await sleep(100);

  const state = window.__checkpointSprint;
  const start = performance.now();
  while (!state.finished && performance.now() - start < 20000) {
    const target = state.checkpoints[state.nextCheckpoint];
    const dx = target.x - state.player.x;
    const dy = target.y - state.player.y;
    const dead = 18;
    setKey('a', dx < -dead);
    setKey('d', dx > dead);
    setKey('w', dy < -dead);
    setKey('s', dy > dead);
    await sleep(32);
  }
  releaseAll();
  await sleep(120);
  return {
    finished: state.finished,
    nextCheckpoint: state.nextCheckpoint,
    progress: document.getElementById('progress').textContent,
    time: document.getElementById('time').textContent,
    best: document.getElementById('best').textContent,
    player: { x: Math.round(state.player.x), y: Math.round(state.player.y) },
  };
}

